169	      minQuotes:               ['RFQ Evaluation', 'PO Issuance'],
170	    };
171	    const currentVersion = (rule.versions ?? []).find((v) => v.versionNumber === rule.currentVersion);
172	    const defKeys = Object.keys(currentVersion?.definition ?? {});
173	    const workflows = new Set<string>();
174	    for (const key of defKeys) {
175	      const mapped = keyToWorkflows[key];
176	      if (mapped) mapped.forEach((w) => workflows.add(w));
177	    }
178	    // If no keys match specific workflows, derive from category as fallback context
179	    if (workflows.size === 0) {
180	      workflows.add(`${rule.category} workflow`);
181	    }
182	    const affectedWorkflows = [...workflows];
183	    const estimatedImpact =
184	      rule.rolloutPercentage < 100
185	        ? `A/B test: ${rule.rolloutPercentage}% of traffic affected`
186	        : 'Full rollout: all users affected';
187	
188	    // Compute concrete diff between current and previous version definitions
189	    const sorted = [...(rule.versions ?? [])].sort((a, b) => b.versionNumber - a.versionNumber);
190	    const currentDef = sorted.find((v) => v.versionNumber === rule.currentVersion)?.definition ?? {};
191	    const previousDef = sorted.find((v) => v.versionNumber === rule.currentVersion - 1)?.definition ?? {};
192	    const allKeys = new Set([...Object.keys(currentDef), ...Object.keys(previousDef)]);
193	    const definitionDiff: { field: string; previous: unknown; current: unknown }[] = [];
194	    for (const key of allKeys) {
195	      const prev = previousDef[key];
196	      const curr = currentDef[key];
197	      if (JSON.stringify(prev) !== JSON.stringify(curr)) {
198	        definitionDiff.push({ field: key, previous: prev ?? null, current: curr ?? null });
199	      }
200	    }
201	
202	    return { rule, affectedWorkflows, estimatedImpact, definitionDiff };
203	  }
