231	    }
232	
233	    const previousVersion = rule.currentVersion - 1;
234	    const now = new Date();
235	
236	    // Mark current version activated
237	    await this.versionRepo.update(
238	      { ruleId: id, versionNumber: rule.currentVersion },
239	      { activatedAt: now },
240	    );
241	
242	    rule.status = RuleStatus.ACTIVE;
243	    await this.ruleRepo.save(rule);
244	
245	    const rollout = this.rolloutRepo.create({
246	      ruleId: id,
247	      fromVersion: Math.max(previousVersion, 1),
248	      toVersion: rule.currentVersion,
249	      status: RolloutStatus.COMPLETED,
250	      initiatedById: userId,
251	      startedAt: now,
252	      completedAt: now,
253	      durationMs: 0,
254	    });
255	    await this.rolloutRepo.save(rollout);
256	
257	    await this.auditLog.log({
258	      userId, action: 'ACTIVATE', entityType: 'BusinessRule', entityId: id,
259	      after: { status: RuleStatus.ACTIVE, version: rule.currentVersion },
260	    });
261	    return { rule, rollout };
