264	  // ── Rollback (must complete in <5 minutes) ────────────────────────────────
265	
266	  async rollbackRule(id: string, userId: string): Promise<{
267	    rule: BusinessRule;
268	    restoredVersion: number;
269	    durationMs: number;
270	    completedWithinLimit: boolean;
271	  }> {
272	    const startedAt = new Date();
273	
274	    const rule = await this.ruleRepo.findOne({ where: { id }, relations: ['versions'] });
275	    if (!rule) throw new NotFoundException('Rule not found');
276	    if (rule.currentVersion <= 1) {
277	      throw new BadRequestException('Cannot rollback — no previous version exists');
278	    }
279	
280	    const targetVersion = rule.currentVersion - 1;
281	
282	    // Run rollback in a transaction for atomicity
283	    await this.dataSource.transaction(async (manager) => {
284	      // Mark current version as rolled back
285	      await manager.update(RuleVersion, { ruleId: id, versionNumber: rule.currentVersion }, {
286	        rolledBackAt: new Date(),
287	      });
288	
289	      // Restore previous version's definition as the "active" definition
290	      const prevVersion = rule.versions.find((v) => v.versionNumber === targetVersion);
291	      if (!prevVersion) {
292	        throw new BadRequestException(`Version ${targetVersion} not found`);
293	      }
294	
295	      // Update rule to point back to previous version
296	      await manager.update(BusinessRule, { id }, {
297	        currentVersion: targetVersion,
298	        status: RuleStatus.ACTIVE,
299	      });
300	    });
301	
302	    const completedAt = new Date();
303	    const durationMs = completedAt.getTime() - startedAt.getTime();
304	    const completedWithinLimit = durationMs < MAX_ROLLBACK_MS;
305	
306	    // Enforce the 5-minute rollback constraint
307	    if (!completedWithinLimit) {
308	      throw new BadRequestException(
309	        `Rollback exceeded 5-minute time limit (took ${Math.round(durationMs / 1000)}s). ` +
310	        'Rollback transaction was committed but flagged as a violation. ' +
311	        'Review and remediate manually.',
312	      );
313	    }
314	
315	    // Record rollout record for the rollback
316	    await this.rolloutRepo.save(
317	      this.rolloutRepo.create({
318	        ruleId: id,
319	        fromVersion: rule.currentVersion,
320	        toVersion: targetVersion,
321	        status: RolloutStatus.ROLLED_BACK,
322	        initiatedById: userId,
323	        startedAt,
324	        completedAt,
325	        rollbackAt: completedAt,
326	        durationMs,
327	      }),
328	    );
329	
330	    await this.auditLog.log({
331	      userId, action: 'ROLLBACK', entityType: 'BusinessRule', entityId: id,
332	      before: { version: rule.currentVersion },
333	      after: { version: targetVersion, durationMs, completedWithinLimit },
334	    });
335	
336	    // Reload to get updated state
337	    const updatedRule = await this.ruleRepo.findOne({ where: { id }, relations: ['versions'] });
338	    return {
339	      rule: updatedRule!,
340	      restoredVersion: targetVersion,
341	      durationMs,
342	      completedWithinLimit,
343	    };
344	  }
345	
346	  // ── Pure helper for unit tests ────────────────────────────────────────────
347	
348	  isRollbackWithinTimeLimit(durationMs: number): boolean {
349	    return durationMs < MAX_ROLLBACK_MS;
350	  }
351	
352	  /**
353	   * Deterministic A/B assignment: given a userId and ruleId, determine whether
354	   * this user falls into the active group based on rolloutPercentage.
355	   * Uses a simple hash-based bucketing approach for consistency.
356	   */
357	  isUserInRolloutGroup(userId: string, ruleId: string, rolloutPercentage: number): boolean {
358	    if (rolloutPercentage >= 100) return true;
359	    if (rolloutPercentage <= 0) return false;
360	    // Simple deterministic hash: sum of char codes mod 100
361	    const combined = `${userId}:${ruleId}`;
362	    let hash = 0;
363	    for (let i = 0; i < combined.length; i++) {
364	      hash = ((hash << 5) - hash + combined.charCodeAt(i)) | 0;
365	    }
366	    const bucket = Math.abs(hash) % 100;
367	    return bucket < rolloutPercentage;
368	  }
369	
370	  /**
371	   * Evaluate a rule for a specific user — respects A/B test configuration.
372	   * Returns the active definition if the user is in the rollout group,
373	   * or null if they're in the control group.
374	   */
375	  async evaluateRuleForUser(ruleId: string, userId: string): Promise<{
376	    inGroup: boolean;
377	    definition: Record<string, unknown> | null;
378	    version: number;
379	  }> {
380	    const rule = await this.ruleRepo.findOne({ where: { id: ruleId }, relations: ['versions'] });
381	    if (!rule) throw new NotFoundException('Rule not found');
382	
383	    const inGroup = rule.isAbTest
384	      ? this.isUserInRolloutGroup(userId, ruleId, rule.rolloutPercentage)
385	      : true;
386	
387	    if (!inGroup) {
388	      return { inGroup: false, definition: null, version: rule.currentVersion };
389	    }
390	
391	    const version = rule.versions.find((v) => v.versionNumber === rule.currentVersion);
392	    return {
393	      inGroup: true,
394	      definition: version?.definition ?? null,
395	      version: rule.currentVersion,
396	    };
397	  }
398	
399	  detectConflict(
400	    newRule: { name: string; category: string; definition: Record<string, unknown> },
401	    existingRules: Array<{ name: string; category: string; definition: Record<string, unknown> }>,
402	  ): { hasConflict: boolean; reason: string | null } {
403	    for (const existing of existingRules) {
404	      if (existing.name === newRule.name) {
405	        return { hasConflict: true, reason: 'Duplicate name in same scope' };
406	      }
407	      if (
408	        existing.category === newRule.category &&
409	        existing.definition.threshold !== undefined &&
410	        newRule.definition.threshold !== undefined &&
411	        existing.definition.threshold === newRule.definition.threshold
412	      ) {
413	        return { hasConflict: true, reason: 'Duplicate threshold in same category' };
414	      }
415	    }
