  `);
  process.stdout.write('✓ Item categories seeded\n');

  // ── Items ────────────────────────────────────────────────────────────────
  const categories = await AppDataSource.query(
    `SELECT id, name FROM item_categories ORDER BY name`,
  );
  const catId = (name: string) =>
